int get_socket_opt(void* ctx, int level, int optname, void* optval, int optlen)
{
  UNITY_LINE_TYPE cmock_line = TEST_LINE_NUM;
  CMOCK_get_socket_opt_CALL_INSTANCE* cmock_call_instance;
  UNITY_SET_DETAIL(CMockString_get_socket_opt);
  cmock_call_instance = (CMOCK_get_socket_opt_CALL_INSTANCE*)CMock_Guts_GetAddressFor(Mock.get_socket_opt_CallInstance);
  Mock.get_socket_opt_CallInstance = CMock_Guts_MemNext(Mock.get_socket_opt_CallInstance);
  if (Mock.get_socket_opt_IgnoreBool)
  {
    UNITY_CLR_DETAILS();
    if (cmock_call_instance == NULL)
      return Mock.get_socket_opt_FinalReturn;
    Mock.get_socket_opt_FinalReturn = cmock_call_instance->ReturnVal;
    return cmock_call_instance->ReturnVal;
  }
  if (!Mock.get_socket_opt_CallbackBool &&
      Mock.get_socket_opt_CallbackFunctionPointer != NULL)
  {
    int cmock_cb_ret = Mock.get_socket_opt_CallbackFunctionPointer(ctx, level, optname, optval, optlen, Mock.get_socket_opt_CallbackCalls++);
    UNITY_CLR_DETAILS();
    return cmock_cb_ret;
  }
  UNITY_TEST_ASSERT_NOT_NULL(cmock_call_instance, cmock_line, CMockStringCalledMore);
  cmock_line = cmock_call_instance->LineNumber;
  if (!cmock_call_instance->ExpectAnyArgsBool)
  {
  if (!cmock_call_instance->IgnoreArg_ctx)
  {
    UNITY_SET_DETAILS(CMockString_get_socket_opt,CMockString_ctx);
    if (cmock_call_instance->Expected_ctx == NULL)
      { UNITY_TEST_ASSERT_NULL(ctx, cmock_line, CMockStringExpNULL); }
    else
      { UNITY_TEST_ASSERT_EQUAL_HEX8_ARRAY(cmock_call_instance->Expected_ctx, ctx, 1, cmock_line, CMockStringMismatch); }
  }
  if (!cmock_call_instance->IgnoreArg_level)
  {
    UNITY_SET_DETAILS(CMockString_get_socket_opt,CMockString_level);
    UNITY_TEST_ASSERT_EQUAL_INT(cmock_call_instance->Expected_level, level, cmock_line, CMockStringMismatch);
  }
  if (!cmock_call_instance->IgnoreArg_optname)
  {
    UNITY_SET_DETAILS(CMockString_get_socket_opt,CMockString_optname);
    UNITY_TEST_ASSERT_EQUAL_INT(cmock_call_instance->Expected_optname, optname, cmock_line, CMockStringMismatch);
  }
  if (!cmock_call_instance->IgnoreArg_optval)
  {
    UNITY_SET_DETAILS(CMockString_get_socket_opt,CMockString_optval);
    if (cmock_call_instance->Expected_optval == NULL)
      { UNITY_TEST_ASSERT_NULL(optval, cmock_line, CMockStringExpNULL); }
    else
      { UNITY_TEST_ASSERT_EQUAL_HEX8_ARRAY(cmock_call_instance->Expected_optval, optval, 1, cmock_line, CMockStringMismatch); }
  }
  if (!cmock_call_instance->IgnoreArg_optlen)
  {
    UNITY_SET_DETAILS(CMockString_get_socket_opt,CMockString_optlen);
    UNITY_TEST_ASSERT_EQUAL_INT(cmock_call_instance->Expected_optlen, optlen, cmock_line, CMockStringMismatch);
  }
  }
  if (Mock.get_socket_opt_CallbackFunctionPointer != NULL)
  {
    cmock_call_instance->ReturnVal = Mock.get_socket_opt_CallbackFunctionPointer(ctx, level, optname, optval, optlen, Mock.get_socket_opt_CallbackCalls++);
  }
  if (cmock_call_instance->ReturnThruPtr_ctx_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(ctx, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)ctx, (void*)cmock_call_instance->ReturnThruPtr_ctx_Val,
      cmock_call_instance->ReturnThruPtr_ctx_Size);
  }
  if (cmock_call_instance->ReturnThruPtr_optval_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(optval, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)optval, (void*)cmock_call_instance->ReturnThruPtr_optval_Val,
      cmock_call_instance->ReturnThruPtr_optval_Size);
  }
  UNITY_CLR_DETAILS();
  return cmock_call_instance->ReturnVal;
}

